// pkg/src/a.ts
// CIRCULAR (D6): a imports b, and b imports a back — a dependency cycle.
import { formatB } from "./b.ts";

export function formatA(x: number): string {
  return "A:" + formatB(x);
}

export const NAME_A = "alpha";

// pkg/src/b.ts
// CIRCULAR (D6): b imports a, closing the a <-> b cycle.
import { NAME_A } from "./a.ts";

export function formatB(x: number): string {
  return NAME_A + ":" + String(x);
}

// pkg/src/index.ts
import { chunk } from "lodash";        // lodash IS used → not a dead dependency
import { formatA } from "./a.ts";

export function run(xs: number[]): string[][] {
  return chunk(xs.map(formatA), 2);
}
// NOTE: `left-pad` is declared in package.json but imported by NO file → dead dependency (D3).

// pkg/src/a.ts
// Clean DAG: a depends on b only (no back-edge).
import { stepB } from "./b.ts";

export function stepA(x: number): number {
  return stepB(x) + 1;
}

// pkg/src/b.ts
// Clean DAG: b depends on c only.
import { stepC } from "./c.ts";

export function stepB(x: number): number {
  return stepC(x) * 2;
}

// pkg/src/c.ts
// Leaf module: uses lodash, imports nothing local.
import { clamp } from "lodash";

export function stepC(x: number): number {
  return clamp(x, 0, 100);
}

// pkg/src/index.ts
import { stepA } from "./a.ts";

export function run(xs: number[]): number[] {
  return xs.map(stepA);
}
